// --- Utility Functions ---

function generateSecureToken() {
  return crypto.randomBytes(CONFIG.TOKEN_BYTE_LENGTH).toString('base64url');
}

function hashToken(token) {
  return crypto.createHash('sha256').update(token, 'utf8').digest('hex');
}

function generateTokenId() {
  return crypto.randomUUID();
}

function createAccessTokenPayload(userId, clientId, scope) {
  const now = Math.floor(Date.now() / 1000);
  return {
    jti: generateTokenId(),
    sub: userId,
    client_id: clientId,
    scope: scope,
    iss: CONFIG.ISSUER,
    iat: now,
    exp: now + CONFIG.ACCESS_TOKEN_EXPIRY_SECONDS,
    token_type: 'access_token',
  };
}

// Simple base64url-encoded signed token (in production, use proper JWT with RS256/ES256)
function signAccessToken(payload) {
  const secret = process.env.TOKEN_SIGNING_SECRET;
  if (!secret || secret.length < 32) {
    throw new Error('TOKEN_SIGNING_SECRET must be set and at least 32 characters');
  }
  const header = Buffer.from(JSON.stringify({ alg: 'HS256', typ: 'at+jwt' })).toString('base64url');
  const body = Buffer.from(JSON.stringify(payload)).toString('base64url');
  const signature = crypto
    .createHmac('sha256', secret)
    .update(`${header}.${body}`)
    .digest('base64url');
  return `${header}.${body}.${signature}`;
}

function verifyAccessToken(token) {
  const secret = process.env.TOKEN_SIGNING_SECRET;
  if (!secret) return null;

  const parts = token.split('.');
  if (parts.length !== 3) return null;

  const [header, body, signature] = parts;
  const expectedSignature = crypto
    .createHmac('sha256', secret)
    .update(`${header}.${body}`)
    .digest('base64url');

  if (!crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expectedSignature))) {
    return null;
  }

  try {
    const payload = JSON.parse(Buffer.from(body, 'base64url').toString('utf8'));
    const now = Math.floor(Date.now() / 1000);
    if (payload.exp && payload.exp < now) return null;
    return payload;
  } catch {
    return null;
  }
}

