// --- Refresh Token Storage (Redis) ---

/*
  Refresh Token Storage Schema:
  
  Key: rt:{hashedToken}
  Value: JSON {
    token_id: string,
    family_id: string,       // Token family for rotation detection
    user_id: string,
    client_id: string,
    scope: string,
    created_at: number,
    expires_at: number,
    revoked: boolean,
    replaced_by: string|null // token_id of the replacement token
  }
  
  Key: rt_family:{family_id}
  Value: JSON {
    user_id: string,
    client_id: string,
    created_at: number,
    revoked: boolean         // If true, entire family is compromised
  }
  
  Key: user_rt:{user_id}
  Value: SET of family_ids
*/

async function storeRefreshToken(tokenHash, tokenData) {
  const key = `rt:${tokenHash}`;
  const ttl = CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS;

  const pipeline = redis.pipeline();
  pipeline.setex(key, ttl, JSON.stringify(tokenData));
  pipeline.setex(`rt_family:${tokenData.family_id}`, ttl, JSON.stringify({
    user_id: tokenData.user_id,
    client_id: tokenData.client_id,
    created_at: tokenData.created_at,
    revoked: false,
  }));
  pipeline.sadd(`user_rt:${tokenData.user_id}`, tokenData.family_id);
  pipeline.expire(`user_rt:${tokenData.user_id}`, ttl);

  await pipeline.exec();
}

async function getRefreshToken(tokenHash) {
  const key = `rt:${tokenHash}`;
  const data = await redis.get(key);
  if (!data) return null;

  try {
    return JSON.parse(data);
  } catch {
    return null;
  }
}

async function revokeRefreshToken(tokenHash) {
  const key = `rt:${tokenHash}`;
  const data = await redis.get(key);
  if (!data) return;

  const tokenData = JSON.parse(data);
  tokenData.revoked = true;
  const ttl = await redis.ttl(key);
  if (ttl > 0) {
    await redis.setex(key, ttl, JSON.stringify(tokenData));
  }
}

async function revokeTokenFamily(familyId) {
  // Revoke the entire token family - indicates potential compromise
  const familyKey = `rt_family:${familyId}`;
  const familyData = await redis.get(familyKey);
  if (!familyData) return;

  const family = JSON.parse(familyData);
  family.revoked = true;
  const ttl = await redis.ttl(familyKey);
  if (ttl > 0) {
    await redis.setex(familyKey, ttl, JSON.stringify(family));
  }

  console.warn(`SECURITY: Token family ${familyId} revoked due to reuse detection for user ${family.user_id}`);
}

async function isTokenFamilyRevoked(familyId) {
  const familyKey = `rt_family:${familyId}`;
  const data = await redis.get(familyKey);
  if (!data) return true; // If family doesn't exist, treat as revoked

  const family = JSON.parse(data);
  return family.revoked === true;
}

async function revokeAllUserTokens(userId) {
  const familyIds = await redis.smembers(`user_rt:${userId}`);
  const pipeline = redis.pipeline();

  for (const familyId of familyIds) {
    const familyKey = `rt_family:${familyId}`;
    // We mark families as revoked rather than deleting, to detect reuse
    const familyData = await redis.get(familyKey);
    if (familyData) {
      const family = JSON.parse(familyData);
      family.revoked = true;
      const ttl = await redis.ttl(familyKey);
      if (ttl > 0) {
        pipeline.setex(familyKey, ttl, JSON.stringify(family));
      }
    }
  }

  await pipeline.exec();
}

async function enforceMaxTokensPerUser(userId) {
  const familyIds = await redis.smembers(`user_rt:${userId}`);
  if (familyIds.length <= CONFIG.MAX_REFRESH_TOKENS_PER_USER) return;

  // Get creation times and sort, revoke oldest
  const families = [];
  for (const fid of familyIds) {
    const data = await redis.get(`rt_family:${fid}`);
    if (data) {
      const family = JSON.parse(data);
      families.push({ family_id: fid, ...family });
    } else {
      // Clean up stale reference
      await redis.srem(`user_rt:${userId}`, fid);
    }
  }

  families.sort((a, b) => a.created_at - b.created_at);
  const toRevoke = families.slice(0, families.length - CONFIG.MAX_REFRESH_TOKENS_PER_USER);

  for (const family of toRevoke) {
    await revokeTokenFamily(family.family_id);
    await redis.srem(`user_rt:${userId}`, family.family_id);
  }
}

