async function storeAuthorizationCode(codeHash, codeData) {
  const key = `authcode:${codeHash}`;
  // Authorization codes expire in 10 minutes (RFC 6749 recommends max 10 min)
  await redis.setex(key, 600, JSON.stringify(codeData));
}

async function consumeAuthorizationCode(codeHash) {
  const key = `authcode:${codeHash}`;
  const data = await redis.get(key);
  if (!data) return null;

  // Delete immediately to prevent reuse
  await redis.del(key);

  try {
    return JSON.parse(data);
  } catch {
    return null;
  }
}

// --- Client Authentication ---

async function authenticateClient(clientId, clientSecret) {
  if (!clientId || !clientSecret) return null;

  const client = CLIENTS.get(clientId);
  if (!client) return null;

  const valid = await bcrypt.compare(clientSecret, client.client_secret_hash);
  if (!valid) return null;

  return client;
}

function parseClientCredentials(req) {
  // Check Authorization header first (preferred)
  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    try {
      const decoded = Buffer.from(authHeader.slice(6), 'base64').toString('utf8');
      const colonIndex = decoded.indexOf(':');
      if (colonIndex === -1) return { clientId: null, clientSecret: null };
      return {
        clientId: decodeURIComponent(decoded.slice(0, colonIndex)),
        clientSecret: decodeURIComponent(decoded.slice(colonIndex + 1)),
      };
    } catch {
      return { clientId: null, clientSecret: null };
    }
  }

  // Fall back to body parameters
  return {
    clientId: req.body.client_id,
    clientSecret: req.body.client_secret,
  };
}

// --- Scope Validation ---

function validateScope(requestedScope, allowedScope) {
  if (!requestedScope) return allowedScope;

  const allowed = new Set(allowedScope.split(' '));
  const requested = requestedScope.split(' ');

  for (const scope of requested) {
    if (!allowed.has(scope)) return null;
  }

  return requestedScope;
}

