async function handleAuthorizationCodeGrant(req, res, client) {
  const { code, redirect_uri, code_verifier } = req.body;

  if (!code) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Authorization code is required',
    });
  }

  const codeHash = hashToken(code);
  const codeData = await consumeAuthorizationCode(codeHash);

  if (!codeData) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid or expired authorization code',
    });
  }

  // Validate client matches
  if (codeData.client_id !== client.client_id) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code was not issued to this client',
    });
  }

  // Validate redirect_uri matches
  if (codeData.redirect_uri !== redirect_uri) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Redirect URI mismatch',
    });
  }

  // Validate PKCE if code_challenge was provided
  if (codeData.code_challenge) {
    if (!code_verifier) {
      return res.status(400).json({
        error: 'invalid_grant',
        error_description: 'Code verifier is required',
      });
    }

    const expectedChallenge = crypto
      .createHash('sha256')
      .update(code_verifier, 'ascii')
      .digest('base64url');

    if (!crypto.timingSafeEqual(
      Buffer.from(expectedChallenge),
      Buffer.from(codeData.code_challenge)
    )) {
      return res.status(400).json({
        error: 'invalid_grant',
        error_description: 'Invalid code verifier',
      });
    }
  }

  // Check code expiration (10 minutes)
  const now = Math.floor(Date.now() / 1000);
  if (now - codeData.created_at > 600) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has expired',
    });
  }

  // Issue tokens
  return await issueTokens(res, codeData.user_id, client.client_id, codeData.scope, null);
}

async function handleRefreshTokenGrant(req, res, client) {
  const { refresh_token, scope } = req.body;

  if (!refresh_token) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Refresh token is required',
    });
  }

  const tokenHash = hashToken(refresh_token);
  const tokenData = await getRefreshToken(tokenHash);

  if (!tokenData) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid refresh token',
    });
  }

  // Check if token is revoked
  if (tokenData.revoked) {
    // A revoked token was reused - this indicates token theft!
    // Revoke the entire token family
    console.warn(`SECURITY ALERT: Revoked refresh token reused. Family: ${tokenData.family_id}, User: ${tokenData.user_id}`);
    await revokeTokenFamily(tokenData.family_id);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Refresh token has been revoked. All sessions in this family have been terminated.',
    });
  }

  // Check if the token family has been revoked (compromise detected)
  if (await isTokenFamilyRevoked(tokenData.family_id)) {
    console.warn(`SECURITY: Attempt to use token from revoked family ${tokenData.family_id}`);
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Session has been terminated due to security concerns',
    });
  }

  // Validate client matches
  if (tokenData.client_id !== client.client_id) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Refresh token was not issued to this client',
    });
  }

  // Check expiration
  const now = Math.floor(Date.now() / 1000);
  if (tokenData.expires_at < now) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Refresh token has expired',
    });
  }

  // Validate scope (can only narrow, not widen)
  let effectiveScope = tokenData.scope;
  if (scope) {
    const originalScopes = new Set(tokenData.scope.split(' '));
    const requestedScopes = scope.split(' ');
    for (const s of requestedScopes) {
      if (!originalScopes.has(s)) {
        return res.status(400).json({
          error: 'invalid_scope',
          error_description: 'Requested scope exceeds original grant',
        });
      }
    }
    effectiveScope = scope;
  }

  // REFRESH TOKEN ROTATION: Revoke the old token and issue a new one
  // This is a critical security measure - if an attacker steals a refresh token,
  // the legitimate user's next refresh will fail, and we detect the compromise.
  await revokeRefreshToken(tokenHash);

  // Issue new tokens with the same family_id
  return await issueTokens(res, tokenData.user_id, client.client_id, effectiveScope, tokenData.family_id);
}

async function issueTokens(res, userId, clientId, scope, familyId) {
  const now = Math.floor(Date.now() / 1000);

  // Generate access token
  const accessTokenPayload = createAccessTokenPayload(userId, clientId, scope);
  const accessToken = signAccessToken(accessTokenPayload);

  // Generate refresh token with rotation
  const refreshToken = generateSecureToken();
  const refreshTokenHash = hashToken(refreshToken);
  const tokenId = generateTokenId();
  const currentFamilyId = familyId || generateTokenId(); // New family if first token

  const refreshTokenData = {
    token_id: tokenId,
    family_id: currentFamilyId,
    user_id: userId,
    client_id: clientId,
    scope: scope,
    created_at: now,
    expires_at: now + CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS,
    revoked: false,
    replaced_by: null,
  };

  await storeRefreshToken(refreshTokenHash, refreshTokenData);
  await enforceMaxTokensPerUser(userId);

  // Set cache control headers
  res.set('Cache-Control', 'no-store');
  res.set('Pragma', 'no-cache');

  return res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: CONFIG.ACCESS_TOKEN_EXPIRY_SECONDS,
    refresh_token: refreshToken,
    scope: scope,
  });
}

// --- Token Revocation Endpoint (RFC 7009) ---
app.post('/revoke',
  tokenRateLimiter,
  [
    body('token').isString().trim().notEmpty().isLength({ max: 200 }),
    body('token_type_hint').optional().isString().isIn(['refresh_token', 'access_token']),
  ],
  async (req, res) => {
    try {
      const errors = validationResult(req);
      if (!errors.isEmpty()) {
        // Per RFC 7009, always return 200
        return res.status(200).json({});
      }

      // Authenticate client
      const { clientId, clientSecret } = parseClientCredentials(req);
      const client = await authenticateClient(clientId, clientSecret);

      if (!client) {
        res.set('WWW-Authenticate', 'Basic');
        return res.status(401).json({
          error: 'invalid_client',
          error_description: 'Client authentication failed',
        });
      }

      const { token } = req.body;
      const tokenHash = hashToken(token);

      // Try to revoke as refresh token
      const refreshTokenData = await getRefreshToken(tokenHash);
      if (refreshTokenData) {
        // Verify the token belongs to this client
        if (refreshTokenData.client_id !== client.client_id) {
          // Per RFC 7009, return 200 even if we can't revoke
          return res.status(200).json({});
        }
        await revokeRefreshToken(tokenHash);
      }

      // Per RFC 7009, always return 200
      res.status(200).json({});
    } catch (err) {
      console.error('Revocation error:', err.message);
      // Per RFC 7009, return 200 even on errors (to not leak info)
      res.status(200).json({});
    }
  }
);

// --- Revoke All User Sessions ---
app.post('/revoke-all',
  tokenRateLimiter,
  [
    body('user_id').isString().trim().notEmpty().isLength({ max: 100 }),
  ],
  async (req, res) => {
    try {
      const errors = validationResult(req);
      if (!errors.isEmpty()) {
        return res.status(400).json({
          error: 'invalid_request',
          error_description: 'Invalid request parameters',
        });
      }

      // Authenticate client
      const { clientId, clientSecret } = parseClientCredentials(req);
      const client = await authenticateClient(clientId, clientSecret);

      if (!client) {
        res.set('WWW-Authenticate', 'Basic');
        return res.status(401).json({
          error: 'invalid_client',
          error_description: 'Client authentication failed',
        });
      }

      const { user_id } = req.body;
      await revokeAllUserTokens(user_id);

      res.json({ message: 'All refresh tokens revoked for user' });
    } catch (err) {
      console.error('Revoke all error:', err.message);
      res.status(500).json({
        error: 'server_error',
        error_description: 'Internal server error',
      });
    }
  }
);

// --- Token Introspection Endpoint (RFC 7662) ---
app.post('/introspect',
  tokenRateLimiter,
  [
    body('token').isString().trim().notEmpty().isLength({ max: 2000 }),
    body('token_type_hint').optional().isString().isIn(['access_token', 'refresh_token']),
  ],
  async (req, res) => {
    try {
      const errors = validationResult(req);
      if (!errors.isEmpty()) {
        return res.json({ active: false });
      }

      // Authenticate client
      const { clientId, clientSecret } = parseClientCredentials(req);
      const client = await authenticateClient(clientId, clientSecret);

      if (!client) {
        res.set('WWW-Authenticate', 'Basic');
        return res.status(401).json({
          error: 'invalid_client',
          error_description: 'Client authentication failed',
        });
      }

      const { token, token_type_hint } = req.body;

      // Try as access token
      if (!token_type_hint || token_type_hint === 'access_token') {
        const payload = verifyAccessToken(token);
        if (payload) {
          return res.json({
            active: true,
            sub: payload.sub,
            client_id: payload.client_id,
            scope: payload.scope,
            iss: payload.iss,
            exp: payload.exp,
            iat: payload.iat,
            jti: payload.jti,
            token_type: 'access_token',
          });
        }
      }

      // Try as refresh token
      if (!token_type_hint || token_type_hint === 'refresh_token') {
        const tokenHash = hashToken(token);
        const tokenData = await getRefreshToken(tokenHash);

        if (tokenData && !tokenData.revoked && tokenData.client_id === client.client_id) {
          const now = Math.floor(Date.now() / 1000);
          if (tokenData.expires_at > now && !(await isTokenFamilyRevoked(tokenData.family_id))) {
            return res.json({
              active: true,
              sub: tokenData.user_id,
              client_id: tokenData.client_id,
              scope: tokenData.scope,
              exp: tokenData.expires_at,
              iat: tokenData.created_at,
              jti: tokenData.token_id,
              token_type: 'refresh_token',
            });
          }
        }
      }

      res.json({ active: false });
    } catch (err) {
      console.error('Introspection error:', err.message);
      res.json({ active: false });
    }
  }
);

// --- Protected Resource Example ---
app.get('/userinfo', async (req, res) => {
  try {
    const authHeader = req.headers.authorization;
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      res.set('WWW-Authenticate', 'Bearer');
      return res.status(401).json({
        error: 'invalid_token',
        error_description: 'Access token required',
      });
    }

    const token = authHeader.slice(7);
    const payload = verifyAccessToken(token);

    if (!payload) {
      res.set('WWW-Authenticate', 'Bearer error="invalid_token"');
      return res.status(401).json({
        error: 'invalid_token',
        error_description: 'Invalid or expired access token',
      });
    }

    res.json({
      sub: payload.sub,
      scope: payload.scope,
      client_id: payload.client_id,
    });
  } catch (err) {
    console.error('Userinfo error:', err.message);
    res.status(500).json({
      error: 'server_error',
      error_description: 'Internal server error',
    });
  }
});

// --- Server Discovery (RFC 8414) ---
app.get('/.well-known/oauth-authorization-server', (req, res) => {
  const baseUrl = process.env.BASE_URL || `http://localhost:${CONFIG.PORT}`;
  res.json({
    issuer: CONFIG.ISSUER,
    authorization_endpoint: `${baseUrl}/authorize`,
    token_endpoint: `${baseUrl}/token`,
    revocation_endpoint: `${baseUrl}/revoke`,
    introspection_endpoint: `${baseUrl}/introspect`,
    userinfo_endpoint: `${baseUrl}/userinfo`,
    response_types_supported: ['code'],
    grant_types_supported: ['authorization_code', 'refresh_token'],
    token_endpoint_auth_methods_supported: ['client_secret_basic', 'client_secret_post'],
    code_challenge_methods_supported: ['S256'],
    revocation_endpoint_auth_methods_supported: ['client_secret_basic', 'client_secret_post'],
    introspection_endpoint_auth_methods_supported: ['client_secret_basic', 'client_secret_post'],
  });
});

// --- 404 Handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'not_found' });
});

// --- Error Handler ---
app.use((err, req, res, _next) => {
  console.error('Unhandled error:', err.message);
  res.status(500).json({
    error: 'server_error',
    error_description: 'Internal server error',
  });
});

// --- Startup ---
async function start() {
  // Validate required environment variables
  if (!process.env.TOKEN_SIGNING_SECRET || process.env.TOKEN_SIGNING_SECRET.length < 32) {
    console.error('FATAL: TOKEN_SIGNING_SECRET environment variable must be set (min 32 chars)');
    console.error('Generate one with: node -e "console.log(require(\'crypto\').randomBytes(64).toString(\'hex\'))"');
    process.exit(1);
  }

  try {
    await redis.ping();
    console.log('Redis connection verified');
  } catch (err) {
    console.error('FATAL: Cannot connect to Redis:', err.message);
    process.exit(1);
  }

  await initializeClients();
  await initializeUsers();

  console.log('Clients and users initialized');

  const server = app.listen(CONFIG.PORT, '127.0.0.1', () => {
    console.log(`OAuth 2.0 Authorization Server listening on port ${CONFIG.PORT}`);
    console.log('Security features enabled:');
    console.log('  - Refresh token rotation (new token on each use)');
    console.log('  - Token family tracking (reuse detection)');
    console.log('  - Hashed token storage in Redis');
    console.log('  - PKCE support (S256)');
    console.log('  - Rate limiting');
    console.log('  - Input validation');
    console.log(`  - Refresh token TTL: ${CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS / 86400} days`);
    console.log(`  - Access token TTL: ${CONFIG.ACCESS_TOKEN_EXPIRY_SECONDS / 60} minutes`);
  });

  // Graceful shutdown
  const shutdown = async (signal) => {
    console.log(`\n${signal} received. Shutting down gracefully...`);
    server.close(async () => {
      await redis.quit();
      console.log('Server shut down');
      process.exit(0);
    });

    // Force shutdown after 10 seconds
    setTimeout(() => {
      console.error('Forced shutdown after timeout');
      process.exit(1);
    }, 10000);
  };

  process.on('SIGTERM', () => shutdown('SIGTERM'));
  process.on('SIGINT', () => shutdown('SIGINT'));
}

start().catch((err) => {
  console.error('Failed to start server:', err);
  process.exit(1);
});

module.exports = { app, redis };